const now = new Date();
const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
const tasks = $input.all().map(item => item.json);

const missed = [];
const deadlineToday = [];
const urgent = [];   // 1 day
const within3 = [];  // 2-3 days
const thisWeek = []; // 4-7 days

for (const task of tasks) {
  if (!task.deadline || !task.deadline.date) continue;

  const dlDate = new Date(task.deadline.date + 'T00:00:00');
  const diffMs = dlDate.getTime() - todayStart.getTime();
  const daysLeft = Math.round(diffMs / (1000 * 60 * 60 * 24));

  const entry = {
    content: task.content,
    deadlineDate: task.deadline.date,
    daysLeft: daysLeft
  };

  if (daysLeft < 0) {
    entry.daysMissed = Math.abs(daysLeft);
    missed.push(entry);
  } else if (daysLeft === 0) {
    deadlineToday.push(entry);
  } else if (daysLeft === 1) {
    urgent.push(entry);
  } else if (daysLeft <= 3) {
    within3.push(entry);
  } else if (daysLeft <= 7) {
    thisWeek.push(entry);
  }
}

missed.sort((a, b) => b.daysMissed - a.daysMissed);
deadlineToday.sort((a, b) => a.content.localeCompare(b.content));
urgent.sort((a, b) => a.content.localeCompare(b.content));
within3.sort((a, b) => a.daysLeft - b.daysLeft);
thisWeek.sort((a, b) => a.daysLeft - b.daysLeft);

const totalCount = missed.length + deadlineToday.length + urgent.length + within3.length + thisWeek.length;

if (totalCount === 0) {
  return [{ json: { hasDeadlines: false, totalCount: 0 } }];
}

// Build HTML email
let html = '<div style="font-family:-apple-system,BlinkMacSystemFont,sans-serif;max-width:600px;margin:0 auto;color:#1a1a1a;">';
html += '<div style="background:#1a1a1a;color:white;padding:20px;border-radius:8px 8px 0 0;">';
html += '<h1 style="margin:0;font-size:20px;">\u23f0 Deadline Early Warning</h1>';
html += '<p style="margin:5px 0 0;opacity:0.8;font-size:14px;">' + totalCount + ' deadline(s) within 7 days</p>';
html += '</div>';
html += '<div style="padding:20px;background:#f9f9f9;border-radius:0 0 8px 8px;">';

// MISSED DEADLINES
if (missed.length > 0 || deadlineToday.length > 0) {
  html += '<h2 style="color:#dc3545;font-size:16px;margin:0 0 12px;text-transform:uppercase;letter-spacing:1px;">\u26a0 DEADLINE TODAY / MISSED</h2>';
  html += '<table style="width:100%;border-collapse:collapse;margin-bottom:20px;">';
  for (const t of missed) {
    html += '<tr style="border-bottom:1px solid #e9ecef;">';
    html += '<td style="padding:8px 4px;"><span style="background:#dc3545;color:white;padding:2px 8px;border-radius:3px;font-size:12px;font-weight:bold;">MISSED</span></td>';
    html += '<td style="padding:8px 4px;"><strong>' + t.content + '</strong></td>';
    html += '<td style="padding:8px 4px;text-align:right;color:#dc3545;font-weight:bold;">MISSED by ' + t.daysMissed + ' day(s)</td>';
    html += '</tr>';
  }
  for (const t of deadlineToday) {
    html += '<tr style="border-bottom:1px solid #e9ecef;">';
    html += '<td style="padding:8px 4px;"><span style="background:#fd7e14;color:white;padding:2px 8px;border-radius:3px;font-size:12px;font-weight:bold;">TODAY</span></td>';
    html += '<td style="padding:8px 4px;"><strong>' + t.content + '</strong></td>';
    html += '<td style="padding:8px 4px;text-align:right;color:#fd7e14;font-weight:bold;">Deadline is TODAY</td>';
    html += '</tr>';
  }
  html += '</table>';
}

// URGENT (1 day)
if (urgent.length > 0) {
  html += '<h2 style="color:#fd7e14;font-size:16px;margin:0 0 12px;text-transform:uppercase;letter-spacing:1px;">\u26a1 URGENT \u2014 1 DAY LEFT</h2>';
  html += '<table style="width:100%;border-collapse:collapse;margin-bottom:20px;">';
  for (const t of urgent) {
    html += '<tr style="border-bottom:1px solid #e9ecef;">';
    html += '<td style="padding:8px 4px;"><strong>' + t.content + '</strong></td>';
    html += '<td style="padding:8px 4px;text-align:right;color:#fd7e14;">deadline ' + t.deadlineDate + ' (1 day left)</td>';
    html += '</tr>';
  }
  html += '</table>';
}

// WITHIN 3 DAYS
if (within3.length > 0) {
  html += '<h2 style="color:#ffc107;font-size:16px;margin:0 0 12px;text-transform:uppercase;letter-spacing:1px;">WITHIN 3 DAYS</h2>';
  html += '<table style="width:100%;border-collapse:collapse;margin-bottom:20px;">';
  for (const t of within3) {
    html += '<tr style="border-bottom:1px solid #e9ecef;">';
    html += '<td style="padding:8px 4px;">' + t.content + '</td>';
    html += '<td style="padding:8px 4px;text-align:right;color:#856404;">deadline ' + t.deadlineDate + ' (' + t.daysLeft + ' days left)</td>';
    html += '</tr>';
  }
  html += '</table>';
}

// THIS WEEK (4-7 days)
if (thisWeek.length > 0) {
  html += '<h2 style="color:#6f42c1;font-size:16px;margin:0 0 12px;text-transform:uppercase;letter-spacing:1px;">THIS WEEK</h2>';
  html += '<table style="width:100%;border-collapse:collapse;margin-bottom:20px;">';
  for (const t of thisWeek) {
    html += '<tr style="border-bottom:1px solid #e9ecef;">';
    html += '<td style="padding:8px 4px;">' + t.content + '</td>';
    html += '<td style="padding:8px 4px;text-align:right;color:#6f42c1;">deadline ' + t.deadlineDate + ' (' + t.daysLeft + ' days left)</td>';
    html += '</tr>';
  }
  html += '</table>';
}

html += '</div></div>';

const subject = '[Deadline Alert] ' + totalCount + ' deadline(s) approaching';

return [{ json: { hasDeadlines: true, totalCount: totalCount, subject: subject, html: html, missedCount: missed.length, todayCount: deadlineToday.length, urgentCount: urgent.length, within3Count: within3.length, thisWeekCount: thisWeek.length } }];
